import java.security.spec.KeySpec;

/**
 * AES encryption utility class providing secure encryption functionality.
 * Uses AES-256 in CBC mode with PKCS5 padding, PBKDF2 key derivation for secure key generation.
 */
public class AESService {

    // AES algorithm constant
    private static final String AES_ALGORITHM = "AES";
    // Cipher transformation using CBC mode and PKCS5 padding
    private static final String CIPHER_TRANSFORMATION = "AES/CBC/PKCS5Padding";
    // Key derivation algorithm using HMAC-SHA256
    private static final String KEY_DERIVATION_ALGORITHM = "PBKDF2WithHmacSHA256";
    // AES key length in bits (256 bits for strong security)
    private static final int KEY_LENGTH = 256;
    // Number of iterations for PBKDF2 key derivation
    private static final int ITERATION_COUNT = 65536;
    // Salt length in bytes (128 bits)
    private static final int SALT_LENGTH = 16;
    // Initialization Vector (IV) length in bytes (matches AES block size of 128 bits)
    private static final int IV_LENGTH = 16;

    /**
     * Encrypts the given data using AES encryption.
     *
     * @param key  The password/key string used to derive the AES encryption key
     * @param data The raw byte array data to encrypt
     * @return Hexadecimal string of the encrypted data (includes salt, IV, and ciphertext)
     * @throws IllegalArgumentException If key is null/empty or data is null
     * @throws RuntimeException         If any encryption-related error occurs
     */
    public static String encrypt(String key, byte[] data) {
        // Validate input parameters
        if (key == null || key.trim().isEmpty()) {
            throw new IllegalArgumentException("Encryption key cannot be null or empty");
        }
        if (data == null) {
            throw new IllegalArgumentException("Data to encrypt cannot be null");
        }

        try {
            // Generate secure random salt for key derivation
            SecureRandom secureRandom = new SecureRandom();
            byte[] salt = new byte[SALT_LENGTH];
            secureRandom.nextBytes(salt);

            // Generate secure random Initialization Vector (IV) for CBC mode
            byte[] iv = new byte[IV_LENGTH];
            secureRandom.nextBytes(iv);

            // Derive AES key from the password using PBKDF2
            SecretKeyFactory keyFactory = SecretKeyFactory.getInstance(KEY_DERIVATION_ALGORITHM);
            KeySpec keySpec = new PBEKeySpec(key.toCharArray(), salt, ITERATION_COUNT, KEY_LENGTH);
            SecretKey derivedKey = keyFactory.generateSecret(keySpec);
            SecretKey aesKey = new SecretKeySpec(derivedKey.getEncoded(), AES_ALGORITHM);

            // Initialize cipher for encryption
            Cipher cipher = Cipher.getInstance(CIPHER_TRANSFORMATION);
            cipher.init(Cipher.ENCRYPT_MODE, aesKey, new IvParameterSpec(iv));

            // Perform encryption
            byte[] ciphertext = cipher.doFinal(data);

            // Combine salt, IV, and ciphertext into a single byte array for output
            byte[] result = new byte[SALT_LENGTH + IV_LENGTH + ciphertext.length];
            System.arraycopy(salt, 0, result, 0, SALT_LENGTH);
            System.arraycopy(iv, 0, result, SALT_LENGTH, IV_LENGTH);
            System.arraycopy(ciphertext, 0, result, SALT_LENGTH + IV_LENGTH, ciphertext.length);

            // Convert combined bytes to hexadecimal string
            return bytesToHex(result);

        } catch (Exception e) {
            // Wrap all encryption-related exceptions into a runtime exception
            throw new RuntimeException("Failed to encrypt data: " + e.getMessage(), e);
        }
    }

    /**
     * Converts a byte array to a hexadecimal string representation.
     *
     * @param bytes The byte array to convert
     * @return Hexadecimal string (lowercase)
     */
    private static String bytesToHex(byte[] bytes) {
        StringBuilder hexBuilder = new StringBuilder();
        for (byte b : bytes) {
            // Format each byte as two hex characters, ensuring leading zero for values < 16
            hexBuilder.append(String.format("%02x", b));
        }
        return hexBuilder.toString();
    }
}
